mapper.select:
SELECT r.id, d.device_id AS deviceId, d.device_name AS deviceName, d.ip_address AS ipAddress, d.location, r.monitor_name AS monitorName, r.value, r.threshold_upper AS thresholdUpper, r.threshold_lower AS thresholdLower, r.alarm_level AS alarmLevel, r.alarm_desc AS alarmDesc, r.collect_time AS collectTime, r.is_processed AS isProcessed, r.process_time AS processTime, r.process_by AS processBy, r.process_description AS processDescription, r.process_method AS processMethod, r.resolved, r.tenant_id AS tenantId FROM power_monitor_record r LEFT JOIN power_device d ON r.device_id = d.id
r.is_alarm = 1
AND r.tenant_id = #{tenantId}
AND d.device_id = #{deviceId}
AND d.device_name LIKE CONCAT('%', #{deviceName}, '%')
AND d.ip_address LIKE CONCAT('%', #{ipAddress}, '%')
AND d.location LIKE CONCAT('%', #{location}, '%')
AND r.alarm_level = #{alarmLevel}
AND r.is_processed = #{isProcessed}
AND r.collect_time >= #{alarmTimeStart}
AND r.collect_time <= #{alarmTimeEnd}
AND r.monitor_name = #{alarmType}
ORDER BY r.collect_time DESC

SELECT pmr.alarm_level as alarmLevel, COUNT(*) as count FROM power_monitor_record pmr WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
GROUP BY pmr.alarm_level

SELECT pmr.monitor_name as monitorName, COUNT(*) as count FROM power_monitor_record pmr WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
GROUP BY pmr.monitor_name

SELECT pd.location, COUNT(*) as count FROM power_monitor_record pmr JOIN power_device pd ON pmr.device_id = pd.id WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
GROUP BY pd.location

SELECT DATE_FORMAT(pmr.collect_time, '%Y-%m-%d') as date, COUNT(*) as count FROM power_monitor_record pmr WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
GROUP BY DATE_FORMAT(pmr.collect_time, '%Y-%m-%d') ORDER BY date

SELECT COUNT(*) as totalAlarms, SUM(CASE WHEN pmr.is_processed = 0 THEN 1 ELSE 0 END) as unprocessedAlarms, SUM(CASE WHEN pmr.resolved = 1 THEN 1 ELSE 0 END) as resolvedAlarms FROM power_monitor_record pmr WHERE pmr.is_alarm = 1
AND pmr.collect_time >= #{startTime}
AND pmr.collect_time <= #{endTime}
AND pmr.tenant_id = #{tenantId}
